                const queue: [number, number][] = [[i, j]];
                visited[i][j] = true;
                let sum = 0;

                while (queue.length > 0) {
                    const [x, y] = queue.shift()!;
                    sum += grid[x][y];
                    const directions = [[0, 1], [1, 0], [0, -1], [-1, 0]];
                    for (const [dx, dy] of directions) {
                        const nx = x + dx;
                        const ny = y + dy;
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && !visited[nx][ny] && grid[nx][ny] > 0) {
                            visited[nx][ny] = true;
                            queue.push([nx, ny]);
                        }
                    }
                }

                if (sum % k === 0) {
                    count++;
                }
            }
        }
    }

    return count;
}
