                    let [x, y] = queue.shift()!;
                    const directions = [[-1, 0], [1, 0], [0, -1], [0, 1]];

                    for (const [dx, dy] of directions) {
                        let nx = x + dx;
                        let ny = y + dy;

                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] !== 0) {
                            grid[nx][ny] = 0;
                            sum += grid[nx][ny];
                            queue.push([nx, ny]);
                        }
                    }
                }

                if (sum % k === 0) {
                    count++;
                }
            }
        }
    }

